209	static int post_process_obj_detect(image_bytes img, struct EEPTPU_RESULT& result)
210	{
211	    clear_objects();
212	    
213	    if ( (result.shape[1] * result.shape[2] * result.shape[3] == 0) || (result.shape[1] != 1) )
214	    {
215	        printf("Nothing detected !\n");
216	        return 0;
217	    }
218	    
219	    for (int i = 0; i < result.shape[2]; i++)
220	    {
221	        const float *values = result.data + i * result.shape[3];
222	
223	        Object object;
224	        object.label = values[0];
225	        object.prob = values[1];
226	        object.x = values[2] * img.w;
227	        object.y = values[3] * img.h;
228	        object.w = values[4] * img.w - object.x;
229	        object.h = values[5] * img.h - object.y;
230	        strcpy(object.obj_class_name, get_class_name_by_label(object.label));
231	        
232	        if (object.x < 0) { object.w += object.x; object.x = 0; }
233	        if (object.y < 0) { object.h += object.y; object.y = 0; }
234	
235	        g_objects.push_back(object);
236	    }
237	   
238	    printf("Detection result: \n");
239	    for (unsigned int i = 0; i < g_objects.size(); i++)
240	    {
241	        const Object &obj = g_objects[i];
242	        printf("    [%d] %d = %.5f at %d %d %d x %d   (%s)\n", i, obj.label, obj.prob,
243	                obj.x, obj.y, obj.w, obj.h, get_class_name_by_label(obj.label));
244	    }
245	        
246	    return 0;
247	}
