249	static image_bytes draw_objects(image_bytes img, const std::vector<Object> &objects)
250	{    
251	    image_bytes image = eepimg_copy_image(img);
252	
253	    for (size_t i = 0; i < objects.size(); i++)
254	    {
255	        const Object &obj = objects[i];
256	        
257	        int x = obj.x;
258	        int y = obj.y;
259	        sprintf(text, "%s %.1f%%", get_class_name_by_label(obj.label), obj.prob * 100);
260	        image = eepimg_draw_text(image, x, y, text);
261	        
262	        image = eepimg_draw_box(image, 
263	                                obj.x, obj.y, 
264	                                obj.x+obj.w, obj.y+obj.h,
265	                                0, 255, 0, 1);
266	    }
267	
268	    return image;
269	}
