326	std::vector<std::string> split(std::string str,std::string pattern)  
327	{  
328	    std::string::size_type pos;  
329	    std::vector<std::string> result;  
330	      
331	    str+=pattern;
332	    int size=str.size();  
333	      
334	    for(int i=0; i<size; i++)  
335	    {  
336	        pos=str.find(pattern,i);  
337	        if((int)pos < size)  
338	        {  
339	            std::string s=str.substr(i,pos-i);  
340	            result.push_back(s);  
341	            i=pos+pattern.size()-1;  
342	        }  
343	    }  
344	    return result;  
