420	int main(int argc, char* argv[])
421	{
422	    int ret; 
423	    ret = getArgs(argc, argv);
424	    if (ret < 0) return ret;
425	    
426	    signal(SIGINT, signal_handler);
427	    signal(SIGTSTP, signal_handler);
428	    signal(SIGSEGV, signal_handler);
429	    signal(SIGFPE, signal_handler);
430	    
431	    char *path_bin = (char*)appargs.bin_path.c_str();
432	    char *path_image = (char*)appargs.input.c_str();
433	    int pixel_order = EEPIMG_PIXEL_BGR;
434	    if (appargs.pixel_order == "RGB") pixel_order = EEPIMG_PIXEL_RGB;
435	    else if (appargs.pixel_order == "BGR") pixel_order = EEPIMG_PIXEL_BGR;
436	    
437	    printf("\n# Embedeep EEPTPU Library Example - Object Detection #\n\n");
438	
439	    ret = eeptpu_init(eep_interface_type, path_bin);
440	    if (ret < 0)
441	    {
442	        printf("EEPTPU init fail.\n");
443	        return ret;
444	    }
445	
446	    printf("Network input shape: [%d,%d,%d,%d]\n", tpu->input_shape[0], tpu->input_shape[1], tpu->input_shape[2], tpu->input_shape[3]);
447	    
448	    // ====== eeptpu init ok, only init one time in program.
449	    
450	    // ====== loop write input and forward if you have many images.
451	    do 
452	    {
453	        image_bytes img_orig;
454	        img_orig = eeptpu_write_input(path_image, tpu->input_shape[1], tpu->input_shape[2], tpu->input_shape[3], pixel_order);
455	        if (eepimg_empty(img_orig) == true)
456	        {
457	            printf("EEPTPU write input fail\n");
458	            return ret;
459	        }
460	        //printf("img_orig: %d,%d,%d\n", img_orig.c, img_orig.h, img_orig.w);
461	        
462	        std::vector<struct EEPTPU_RESULT> results;
463	        double st = get_current_time();
464	        double et;
465	
466	        // sync forward mode
467	        ret = tpu->eeptpu_forward(results);
468	        if (ret < 0) 
469	        {
470	            printf("eeptpu forward fail, ret = %d\n", ret);
471	            return ret;
472	        }   
473	        
474	        et = get_current_time();
475	        printf("EEPTPU forward ok, cost time(hw+sw): %.3f ms\n", et-st);    
476	        unsigned int hwus = tpu->eeptpu_get_tpu_forward_time();
477	        printf("EEPTPU hardware cost: %.3f ms\n", (float)hwus/1000);
478	    
479	        if (results.size() == 0)
480	        {
481	            printf("Nothing detected. \n");
482	        }
483	        else
484	        {
485	            printf("Result count: %d\n", (int)results.size());
486	            for(unsigned int i = 0; i < results.size(); i++)
487	            {
488	                printf("    results[%d]: %d,%d,%d\n", i, results[i].shape[1], results[i].shape[2], results[i].shape[3]);
489	            }
490	
491	            // post process for yolo3/yolo4/mobilenet-ssd, not suitable for yolo5
492	            ret = post_process_obj_detect(img_orig, results[0]);
493	            if (ret < 0) return ret;
494	            
495	            image_bytes final_image = draw_objects(img_orig, g_objects);
496	            eepimg_save("./objdet.jpg", final_image);
497	            printf("Saved result image to: ./objdet.jpg\n");
498	            if (eepimg_empty(final_image) == false) eepimg_free(final_image);        
499	        }
500	
501	        eepimg_free(img_orig);
502	        
503	        for(unsigned int i = 0; i < results.size(); i++)
504	        {
505	            free(results[i].data);
506	        }
507	        results.clear();
508	        
509	    }while(0);
510	    
511	    // all images done, close eeptpu.
512	    tpu->eeptpu_close();        
513	    clear_objects();
514	    
515	    printf("\nAll done\n");
516	    
517	    return 0;
518	}
